module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output wire				wfull,
    output wire				rempty,
    output reg [WIDTH-1:0]	rdata
);

reg [ADDR_WIDTH-1:0] wp, rp;

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wp <= 0;
    end else if (winc) begin
        wp <= wp + 1;
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rp <= 0;
    end else if (rinc) begin
        rp <= rp + 1;
    end
end

reg [WIDTH-1:0] ram [DEPTH-1:0];

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        ram[wp] <= 0;
    end else begin
        ram[wp] <= wdata;
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rdata <= 0;
    end else begin
        rdata <= ram[rp];
    end
end

assign wfull = (wp ^ {~rp[ADDR_WIDTH-1], rp[ADDR_WIDTH-2:0]}) == {1'b1, {ADDR_WIDTH-2{1'b0}}};
assign rempty = wp == rp;

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule
